#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MOD 1000000007
#define P 23
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, D;
        scanf("%d %d", &N, &D);
        long long X = 0;
        for (int i = 0; i < N; i++) {
            X = X * 10 + D;
        }
        long long Y = X * X;
        long long hash = 0;
        int p = 1;
        while (Y > 0) {
            hash = (hash + p * (Y % 10)) % MOD;
            p = (p * P) % MOD;
            Y /= 10;
        }
        printf("%lld\n", hash);
    }
    return 0;
}

