const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let input = [];
rl.on('line', function(line) {
    input.push(line);
}).on('close', function() {
    let T = +input[0];
    let i = 1;
    while (T-- > 0) {
        let [N, D] = input[i++].split(' ').map(x => +x);
        let X = 0;
        for (let j = 0; j < N; j++) {
            X = X * 10 + D;
        }
        let Y = X * X;
        let hash = 0;
        let p = 1;
        while (Y > 0) {
            hash = (hash + p * (Y % 10)) % 1000000007;
            p = (p * 23) % 1000000007;
            Y = Math.floor(Y / 10);
        }
        console.log(hash);
    }
});
